(function () {
  'use strict';

  var host = window.location.hostname;
  var isProductionHost = host === 'lagobello.com' || host === 'www.lagobello.com';

  // This is only for local/staging/path-prefix previews. Production keeps the
  // absolute canonical/share/schema URLs generated by Hugo untouched.
  if (isProductionHost) {
    return;
  }

  var siteRoots = {
    blog: true,
    builders: true,
    contact: true,
    faq: true,
    'interactive-map': true,
    lots: true,
    school: true,
    tools: true,
    visit: true,
    waterfront: true
  };

  function previewPrefix() {
    var parts = window.location.pathname.split('/').filter(Boolean);
    if (!parts.length || siteRoots[parts[0]]) {
      return '';
    }
    return '/' + parts[0];
  }

  function rewriteLagobelloLinks() {
    var prefix = previewPrefix();
    document.querySelectorAll('a[href]').forEach(function (anchor) {
      var raw = anchor.getAttribute('href');
      if (!raw) {
        return;
      }

      var url;
      try {
        url = new URL(raw, window.location.href);
      } catch (error) {
        return;
      }

      if (url.hostname !== 'lagobello.com' && url.hostname !== 'www.lagobello.com') {
        return;
      }

      anchor.setAttribute('href', prefix + url.pathname + url.search + url.hash);
    });
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', rewriteLagobelloLinks);
  } else {
    rewriteLagobelloLinks();
  }
})();
